int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int a[N]; for (int i = 0; i < N; i++) scanf("%d", &a[i]);
        int maxJump = 0;
        for (int i = 1; i <= 100000; i++) {
            int count = 0;
            for (int j = 0; j < N; j++) {
                if (i % a[j] == 0) count++;
            }
            if (count > 0) maxJump = i;
        }
        printf("%d\n", maxJump);
    }
    return 0;
}

