const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\s+');
let T = parseInt(input.shift());
while (T--) {
    let N = parseInt(input.shift());
    let a = input.splice(0, N).map(Number);
    let maxJump = 0;
    for (let i = 1; i <= 100000; i++) {
        let count = 0;
        for (let j = 0; j < N; j++) {
            if (i % a[j] == 0) count++;
        }
        if (count > 0) maxJump = i;
    }
    console.log(maxJump);
}
